describe("Temporal.Now",()=>{describe("arithmetic methods",()=>{it("instant() returns a Temporal.Instant",()=>{let e=Temporal.Now.instant();expect(e).toBeInstanceOf(Temporal.Instant)}),it("plainDateISO() returns a Temporal.PlainDate",()=>{let e=Temporal.Now.plainDateISO();expect(e).toBeInstanceOf(Temporal.PlainDate)}),it("plainDateTimeISO() returns a Temporal.PlainDateTime",()=>{let e=Temporal.Now.plainDateTimeISO();expect(e).toBeInstanceOf(Temporal.PlainDateTime)}),it("plainTimeISO() returns a Temporal.PlainTime",()=>{let e=Temporal.Now.plainTimeISO();expect(e).toBeInstanceOf(Temporal.PlainTime)}),it("zonedDateTimeISO() returns a Temporal.ZonedDateTime",()=>{let e=Temporal.Now.zonedDateTimeISO();expect(e).toBeInstanceOf(Temporal.ZonedDateTime)})}),describe("properties",()=>{it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(Temporal.Now)).toBe("[object Temporal.Now]")})})});
